@RestController
@RequestMapping("/api/v1/patients/{patientId}/appointments")
public class PatientAppointmentController {

    @GetMapping
    public ResponseEntity<GenericResponse<List<AppointmentResponse>>> list(
            @PathVariable Long patientId) {
        List<AppointmentResponse> appointments = service.findByPatient(patientId);
        return ResponseEntity.ok(GenericResponse.success(appointments));
    }

    @PostMapping
    public ResponseEntity<GenericResponse<AppointmentResponse>> create(
            @PathVariable Long patientId,
            @Valid @RequestBody CreateAppointmentRequest request) {
        AppointmentResponse created = service.schedule(patientId, request);
        return ResponseEntity.status(HttpStatus.CREATED).body(GenericResponse.success(created));
    }
}

