@RestController
@RequestMapping("/api/v1/leads")
@Tag(name = "Leads", description = "Lead tracking and conversion")
public class LeadController {

    @GetMapping
    public ResponseEntity<GenericResponse<Page<LeadResponse>>> getAll(
            @RequestParam(required = false) LeadStatus status,
            @PageableDefault(size = 10) Pageable pageable) {
        return ResponseEntity.ok(GenericResponse.success(service.findAll(status, pageable)));
    }

    @PostMapping("/{id}/convert")
    @Operation(summary = "Convert qualified lead to customer contact")
    public ResponseEntity<GenericResponse<ContactResponse>> convert(@PathVariable Long id) {
        ContactResponse contact = service.convertLead(id);
        return ResponseEntity.ok(GenericResponse.success("Lead converted", contact));
    }
}

